from dataclasses import dataclass, field
from typing import Optional

@dataclass
class AgentGoal:
    objective: str
    success_criteria: list[str]
    constraints: list[str] = field(default_factory=list)
    scope: Optional[str] = None
    max_steps: int = 20
    max_tokens: int = 100_000

    def is_complete(self, results: list[dict]) -> bool:
        """Cheap heuristic check — ask the LLM verifier for a real check."""
        return len(results) > 0 and all(
            r.get("status") == "success" for r in results
        )

    def to_prompt_context(self) -> str:
        lines = [f"Objective: {self.objective}"]
        lines.append("Success criteria:")
        for c in self.success_criteria:
            lines.append(f"  - {c}")
        if self.constraints:
            lines.append("Constraints:")
            for c in self.constraints:
                lines.append(f"  - {c}")
        if self.scope:
            lines.append(f"Scope: {self.scope}")
        lines.append(f"Step budget: {self.max_steps}")
        return "\n".join(lines)

SMART_VALIDATE_PROMPT = """Evaluate this agent goal against SMART criteria.

{goal_context}

For each criterion, output true/false and a one-sentence reason.
Respond with JSON:
{{
  "specific": {{"pass": bool, "reason": str}},
  "measurable": {{"pass": bool, "reason": str}},
  "achievable": {{"pass": bool, "reason": str}},
  "relevant": {{"pass": bool, "reason": str}},
  "time_bound": {{"pass": bool, "reason": str}},
  "ready": bool
}}
"""

@dataclass
class SMARTResult:
    specific: bool
    measurable: bool
    achievable: bool
    relevant: bool
    time_bound: bool
    reasons: dict[str, str]

    @property
    def ready(self) -> bool:
        return all([self.specific, self.measurable, self.achievable,
                    self.relevant, self.time_bound])

    def failures(self) -> list[str]:
        result = []
        for attr in ["specific","measurable","achievable","relevant","time_bound"]:
            if not getattr(self, attr):
                result.append(f"{attr}: {self.reasons[attr]}")
        return result


def validate_smart(
    client: anthropic.Anthropic,
    goal: AgentGoal,
) -> SMARTResult:
    prompt = SMART_VALIDATE_PROMPT.format(
        goal_context=goal.to_prompt_context()
    )
    resp = client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=512,
        messages=[{"role":"user","content":prompt}],
    )
    raw = resp.content[0].text
    m = re.search(r"\{.*\}", raw, re.DOTALL)
    data = json.loads(m.group()) if m else {}
    reasons = {k: data.get(k,{}).get("reason","") for k in
               ["specific","measurable","achievable","relevant","time_bound"]}
    return SMARTResult(
        specific=data.get("specific",{}).get("pass", False),
        measurable=data.get("measurable",{}).get("pass", False),
        achievable=data.get("achievable",{}).get("pass", False),
        relevant=data.get("relevant",{}).get("pass", False),
        time_bound=data.get("time_bound",{}).get("pass", False),
        reasons=reasons,
    )
